module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    // Define the parameter values
    parameter IDLE = 3'd0;
    parameter START = 3'd1;
    parameter SUB = 3'd2;
    parameter SEL = 3'd3;
    parameter SHIFT = 3'd4;
    parameter DONE = 3'd5;

    // Define the registers
    reg [2:0] state, next_state;
    reg [3:0] cnt;
    reg start_cnt;
    reg [7:0] neg_divisor;
    reg [15:0] sr;

    // Define the wires
    wire [7:0] sub_result;
    wire [7:0] mux_result;
    wire [7:0] add_result;
    wire [7:0] abs_dividend;
    wire [7:0] abs_divisor;
    wire cout1;
    wire cout2;
    wire cout3;
    wire cout4;
    wire cout5;
    wire cout6;
    wire cout7;
    wire cout8;
    wire carry;

    // Get the absolute value of the dividend
    assign abs_dividend = (sign & dividend[7]) ? ~dividend + 1'b1 : dividend;

    // Get the absolute value of the divisor
    assign abs_divisor = (sign & divisor[7]) ? ~divisor + 1'b1 : divisor;

    // Update the result when res_valid is high and res_ready is low
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 1'b0;
        end else if (state == DONE) begin
            res_valid <= 1'b1;
        end else if (res_valid & res_ready) begin
            res_valid <= 1'b0;
        end
    end

    // Update the result
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            result <= 16'b0;
        end else if (state == DONE) begin
            result <= {sr[7:0], sr[15:8]};
        end
    end

    // Update the shift register
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            sr <= 16'b0;
        end else if (opn_valid & ~res_valid) begin
            sr <= {abs_dividend, 8'b0};
        end else if (start_cnt) begin
            if (cnt == 4'b1000) begin
                sr <= {1'b0, sr[15:1]};
            end else begin
                sr <= {carry, sr[15:1]};
            end
        end
    end

    // Update the counter and start_cnt
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            cnt <= 4'b0;
            start_cnt <= 1'b0;
        end else if (opn_valid & ~res_valid) begin
            cnt <= 4'b1;
            start_cnt <= 1'b1;
        end else if (start_cnt) begin
            if (cnt == 4'b1000) begin
                cnt <= 4'b0;
                start_cnt <= 1'b0;
            end else begin
                cnt <= cnt + 1'b1;
            end
        end
    end

    // Update the neg_divisor
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            neg_divisor <= 8'b0;
        end else if (opn_valid & ~res_valid) begin
            neg_divisor <= ~abs_divisor + 1'b1;
        end
    end

    // Update the subtraction
    assign sub_result = sr[7:0] + neg_divisor;

    // Update the mux
    assign mux_result = (sub_result[7] == 1'b1) ? sr[7:0] : sub_result;

    // Update the carry
    assign carry = (sub_result[7] == 1'b1) ? 1'b0 : 1'b1;

    // FSM state update
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // FSM next state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (opn_valid) begin
                    next_state = START;
                end else begin
                    next_state = IDLE;
                end
            end
            START: begin
                next_state = SUB;
            end
            SUB: begin
                next_state = SEL;
            end
            SEL: begin
                next_state = SHIFT;
            end
            SHIFT: begin
                if (cnt == 4'b1000) begin
                    next_state = DONE;
                end else begin
                    next_state = SUB;
                end
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end
endmodule
